import React, { useState, useEffect } from 'react';
import axios from 'axios';

const Home = () => {
    const [artisans, setArtisans] = useState([]);

    useEffect(() => {
        axios.get('http://localhost:5000/api/artisans/top')
            .then(res => setArtisans(res.data))
            .catch(err => console.error("Erreur artisans:", err));
    }, []);

    const renderStars = (note) => {
        const stars = [];
        for (let i = 1; i <= 5; i++) {
            stars.push(
                <span key={i} style={{ color: i <= note ? '#ffc107' : '#e4e5e9' }}>★</span>
            );
        }
        return stars;
    };

    return (
        <div className="container py-5">
         
            <section className="mb-5 px-3">
                <h2 className="fw-bold mb-5" style={{ color: '#004a99' }}>Comment trouver mon artisan ?</h2>
                
                <div className="row row-cols-1 row-cols-md-4 g-4 text-start">
                    <div className="col">
                        <div className="d-flex align-items-start h-100">
                            <span className="badge rounded-circle bg-primary me-3 mt-1 d-flex align-items-center justify-content-center" style={{ width: '25px', height: '25px' }}>1</span>
                            <p className="mb-0">Choisir la catégorie d’artisanat dans le menu.</p>
                        </div>
                    </div>
                    <div className="col">
                        <div className="d-flex align-items-start h-100">
                            <span className="badge rounded-circle bg-primary me-3 mt-1 d-flex align-items-center justify-content-center" style={{ width: '25px', height: '25px' }}>2</span>
                            <p className="mb-0">Choisir un artisan.</p>
                        </div>
                    </div>
                    <div className="col">
                        <div className="d-flex align-items-start h-100">
                            <span className="badge rounded-circle bg-primary me-3 mt-1 d-flex align-items-center justify-content-center" style={{ width: '25px', height: '25px' }}>3</span>
                            <p className="mb-0">Le contacter via le formulaire de contact.</p>
                        </div>
                    </div>
                    <div className="col">
                        <div className="d-flex align-items-start h-100">
                            <span className="badge rounded-circle bg-primary me-3 mt-1 d-flex align-items-center justify-content-center" style={{ width: '25px', height: '25px' }}>4</span>
                            <p className="mb-0">Une réponse sera apportée sous 48h.</p>
                        </div>
                    </div>
                </div>
            </section>

            <hr className="my-5 opacity-25" />

            <h2 className="text-center mb-5 fw-bold" style={{ color: '#004a99' }}>
                Artisans du mois
            </h2>

            <div className="row g-4">
                {artisans.length > 0 ? (
                    artisans.map(artisan => (
                        <div className="col-12 col-md-4" key={artisan.id}>
                            <div className="card h-100 border-0 shadow-sm text-center p-3">
                                <div className="card-body">
                                    <h5 className="card-title fw-bold">{artisan.nom || artisan.name}</h5>
                                    <div className="mb-2">
                                        {renderStars(artisan.note)}
                                        <small className="ms-2 text-muted">({artisan.note}/5)</small>
                                    </div>
                                    <p className="card-text text-secondary small">
                                        <strong>Spécialité :</strong> {artisan.specialite || "Artisan"}<br/>
                                        <strong>Localisation :</strong> {artisan.lieu || artisan.location}
                                    </p>
                                    <button className="btn btn-primary rounded-pill px-4 mt-3" style={{ backgroundColor: '#0082c3', border: 'none' }}>
                                        Voir le profil
                                    </button>
                                </div>
                            </div>
                        </div>
                    ))
                ) : (
                    <p className="text-center">Chargement des meilleurs artisans...</p>
                )}
            </div>
        </div>
    );
};

export default Home;
